SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;
DELETE FROM content_blocks;
DELETE FROM lessons;
DELETE FROM levels;
DELETE FROM stages;
DELETE FROM source_documents;
SET FOREIGN_KEY_CHECKS = 1;



-- ============================================================================
-- database/phase2-realtime.sql
-- ============================================================================
CREATE TABLE IF NOT EXISTS realtime_rooms (
    id CHAR(36) PRIMARY KEY DEFAULT (UUID()),
    room_code VARCHAR(80) NOT NULL UNIQUE,
    title VARCHAR(255) NOT NULL,
    language_code VARCHAR(10) NOT NULL,
    level_number INT NOT NULL,
    agora_channel_name VARCHAR(120) NOT NULL UNIQUE,
    password_hash VARCHAR(255) NULL,
    status VARCHAR(32) NOT NULL DEFAULT 'OPEN',
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS realtime_room_participants (
    id CHAR(36) PRIMARY KEY DEFAULT (UUID()),
    room_id CHAR(36) NOT NULL,
    user_id CHAR(36) NULL,
    anonymous_uid VARCHAR(120) NULL,
    display_name VARCHAR(120) NOT NULL,
    role_name VARCHAR(32) NOT NULL DEFAULT 'ANONYMOUS',
    mic_enabled BOOLEAN NOT NULL DEFAULT FALSE,
    hand_raised BOOLEAN NOT NULL DEFAULT FALSE,
    joined_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    left_at TIMESTAMP NULL,
    CONSTRAINT fk_realtime_participants_room FOREIGN KEY (room_id) REFERENCES realtime_rooms(id) ON DELETE CASCADE,
    CONSTRAINT fk_realtime_participants_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS realtime_latency_samples (
    id CHAR(36) PRIMARY KEY DEFAULT (UUID()),
    room_id CHAR(36) NOT NULL,
    participant_id CHAR(36) NULL,
    round_trip_ms INT NOT NULL,
    sampled_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_latency_room FOREIGN KEY (room_id) REFERENCES realtime_rooms(id) ON DELETE CASCADE,
    CONSTRAINT fk_latency_participant FOREIGN KEY (participant_id) REFERENCES realtime_room_participants(id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



-- ============================================================================
-- database/phase3-lms.sql
-- ============================================================================
CREATE TABLE IF NOT EXISTS mentor_material_pins (
    id CHAR(36) PRIMARY KEY DEFAULT (UUID()),
    mentor_user_id CHAR(36) NULL,
    material_title VARCHAR(255) NOT NULL,
    language_code VARCHAR(10) NOT NULL,
    stage_number INT NOT NULL,
    level_number INT NULL,
    pinned_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_material_pins_mentor FOREIGN KEY (mentor_user_id) REFERENCES users(id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS learner_progress (
    id CHAR(36) PRIMARY KEY DEFAULT (UUID()),
    learner_user_id CHAR(36) NULL,
    anonymous_uid VARCHAR(120) NULL,
    display_name VARCHAR(120) NOT NULL,
    language_code VARCHAR(10) NOT NULL,
    stage_number INT NOT NULL,
    level_number INT NOT NULL,
    sub_level VARCHAR(40) NOT NULL DEFAULT 'WARM_UP',
    sub_level_started_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    CONSTRAINT fk_learner_progress_user FOREIGN KEY (learner_user_id) REFERENCES users(id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS lms_transition_events (
    id CHAR(36) PRIMARY KEY DEFAULT (UUID()),
    learner_progress_id CHAR(36) NOT NULL,
    from_sub_level VARCHAR(40) NOT NULL,
    to_sub_level VARCHAR(40) NOT NULL,
    pattern_name VARCHAR(80) NOT NULL DEFAULT 'State Pattern',
    transitioned_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_transition_progress FOREIGN KEY (learner_progress_id) REFERENCES learner_progress(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;




-- ============================================================================
-- database/phase4-monetization.sql
-- ============================================================================
CREATE TABLE IF NOT EXISTS wallet_accounts (
    id CHAR(36) PRIMARY KEY DEFAULT (UUID()),
    user_id CHAR(36) NULL,
    external_owner_id VARCHAR(120) NOT NULL UNIQUE,
    balance DECIMAL(18,2) NOT NULL DEFAULT 0,
    currency_code VARCHAR(10) NOT NULL DEFAULT 'VND',
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    CONSTRAINT fk_wallet_user FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS wallet_transactions (
    id CHAR(36) PRIMARY KEY DEFAULT (UUID()),
    wallet_id CHAR(36) NOT NULL,
    transaction_type VARCHAR(40) NOT NULL,
    amount DECIMAL(18,2) NOT NULL,
    provider_reference VARCHAR(120) NULL,
    status VARCHAR(32) NOT NULL DEFAULT 'COMMITTED',
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_wallet_transactions_wallet FOREIGN KEY (wallet_id) REFERENCES wallet_accounts(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS gift_transactions (
    id CHAR(36) PRIMARY KEY DEFAULT (UUID()),
    from_wallet_id CHAR(36) NOT NULL,
    to_wallet_id CHAR(36) NOT NULL,
    room_code VARCHAR(80) NULL,
    amount DECIMAL(18,2) NOT NULL,
    message VARCHAR(255) NULL,
    realtime_event VARCHAR(80) NOT NULL DEFAULT 'gift:sent',
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_gift_from_wallet FOREIGN KEY (from_wallet_id) REFERENCES wallet_accounts(id) ON DELETE RESTRICT,
    CONSTRAINT fk_gift_to_wallet FOREIGN KEY (to_wallet_id) REFERENCES wallet_accounts(id) ON DELETE RESTRICT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS podcast_recordings (
    id CHAR(36) PRIMARY KEY DEFAULT (UUID()),
    creator_user_id CHAR(36) NULL,
    creator_external_id VARCHAR(120) NOT NULL,
    room_code VARCHAR(80) NOT NULL,
    title VARCHAR(255) NOT NULL,
    storage_uri VARCHAR(500) NOT NULL,
    duration_seconds INT NOT NULL,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_podcast_creator FOREIGN KEY (creator_user_id) REFERENCES users(id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



-- ============================================================================
-- database/phase5-stress-evaluation.sql
-- ============================================================================
CREATE TABLE IF NOT EXISTS stress_test_runs (
    id CHAR(36) PRIMARY KEY DEFAULT (UUID()),
    run_name VARCHAR(160) NOT NULL,
    target_virtual_users INT NOT NULL,
    p95_latency_ms INT NULL,
    failure_rate DECIMAL(8,4) NULL,
    notes TEXT NULL,
    started_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    completed_at TIMESTAMP NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS cross_testing_reports (
    id CHAR(36) PRIMARY KEY DEFAULT (UUID()),
    tester_group VARCHAR(120) NOT NULL,
    tested_group VARCHAR(120) NOT NULL,
    tested_feature VARCHAR(160) NOT NULL,
    result VARCHAR(32) NOT NULL DEFAULT 'PENDING',
    issue_summary TEXT NULL,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


-- ============================================================================
-- phase5-realtime-chat-record.sql — Chat & Recording (Phase 5 Enhancement)
-- ============================================================================
CREATE TABLE IF NOT EXISTS room_messages (
    id CHAR(36) PRIMARY KEY DEFAULT (UUID()),
    room_id CHAR(36) NOT NULL,
    participant_id CHAR(36) NULL,
    user_id VARCHAR(120) NOT NULL,
    display_name VARCHAR(120) NOT NULL,
    message TEXT NOT NULL,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_room_messages_room FOREIGN KEY (room_id) REFERENCES realtime_rooms(id) ON DELETE CASCADE,
    CONSTRAINT fk_room_messages_participant FOREIGN KEY (participant_id) REFERENCES realtime_room_participants(id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE INDEX idx_room_messages_room_created ON room_messages(room_id, created_at);

CREATE TABLE IF NOT EXISTS recording_logs (
    id CHAR(36) PRIMARY KEY DEFAULT (UUID()),
    room_id CHAR(36) NOT NULL,
    started_by VARCHAR(120) NOT NULL,
    started_by_display_name VARCHAR(120) NOT NULL,
    status VARCHAR(32) NOT NULL DEFAULT 'RECORDING',
    storage_uri VARCHAR(500) NULL,
    duration_seconds INT NULL,
    started_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    stopped_at TIMESTAMP NULL,
    CONSTRAINT fk_recording_logs_room FOREIGN KEY (room_id) REFERENCES realtime_rooms(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE INDEX idx_recording_logs_room ON recording_logs(room_id, started_at);
