INSERT INTO content_blocks (lesson_id, block_type, content_text, sort_order) SELECT le.id, 'question', 'Q1: 自信对一个人有什么影响？👉 自信可以让人更勇敢面对挑战。👉 也可以提高成功的可能性。', 1 FROM lessons le JOIN levels lv ON lv.id = le.level_id JOIN stages s ON s.id = lv.stage_id JOIN languages l ON l.id = s.language_id WHERE l.code = 'zh' AND s.stage_number = 3 AND lv.level_number = 99 AND le.sequence_number = 1 ON DUPLICATE KEY UPDATE block_type = VALUES(block_type), content_text = VALUES(content_text);
INSERT INTO content_blocks (lesson_id, block_type, content_text, sort_order) SELECT le.id, 'question', 'Q2: 如何建立自信？👉 通过不断成功的小经验。👉 也可以通过努力提高能力。', 2 FROM lessons le JOIN levels lv ON lv.id = le.level_id JOIN stages s ON s.id = lv.stage_id JOIN languages l ON l.id = s.language_id WHERE l.code = 'zh' AND s.stage_number = 3 AND lv.level_number = 99 AND le.sequence_number = 1 ON DUPLICATE KEY UPDATE block_type = VALUES(block_type), content_text = VALUES(content_text);
INSERT INTO levels (stage_id, level_number, title) SELECT s.id, 100, 'Level 100' FROM stages s JOIN languages l ON l.id = s.language_id WHERE l.code = 'zh' AND s.stage_number = 3 ON DUPLICATE KEY UPDATE title = VALUES(title);
INSERT INTO lessons (level_id, sequence_number, title) SELECT lv.id, 1, '人生观' FROM levels lv JOIN stages s ON s.id = lv.stage_id JOIN languages l ON l.id = s.language_id WHERE l.code = 'zh' AND s.stage_number = 3 AND lv.level_number = 100 ON DUPLICATE KEY UPDATE title = VALUES(title);
INSERT INTO content_blocks (lesson_id, block_type, content_text, sort_order) SELECT le.id, 'question', 'Q1: 你的人生观是什么？👉 我认为应该努力工作，同时也要享受生活。👉 人生不仅要成功，也要快乐。', 1 FROM lessons le JOIN levels lv ON lv.id = le.level_id JOIN stages s ON s.id = lv.stage_id JOIN languages l ON l.id = s.language_id WHERE l.code = 'zh' AND s.stage_number = 3 AND lv.level_number = 100 AND le.sequence_number = 1 ON DUPLICATE KEY UPDATE block_type = VALUES(block_type), content_text = VALUES(content_text);
INSERT INTO content_blocks (lesson_id, block_type, content_text, sort_order) SELECT le.id, 'question', 'Q2: 你觉得什么样的人生是成功的？👉 我觉得实现目标的人生是成功的。👉 能够让自己和家人幸福就是成功。', 2 FROM lessons le JOIN levels lv ON lv.id = le.level_id JOIN stages s ON s.id = lv.stage_id JOIN languages l ON l.id = s.language_id WHERE l.code = 'zh' AND s.stage_number = 3 AND lv.level_number = 100 AND le.sequence_number = 1 ON DUPLICATE KEY UPDATE block_type = VALUES(block_type), content_text = VALUES(content_text);
